from langgraph.prebuilt import create_react_agent
from langchain_anthropic import ChatAnthropic
from langchain_core.tools import tool

# Define tools
@tool
def search(query: str) -> str:
    """Search the web for information."""
    return f"Results for: {query}"

@tool
def calculator(expression: str) -> str:
    """Calculate a mathematical expression."""
    try:
        return str(eval(expression))
    except Exception as e:
        return f"Error: {e}"

# Create ReAct agent
model = ChatAnthropic(model="claude-sonnet-4-5")
tools = [search, calculator]

agent = create_react_agent(model, tools)

# Run
result = agent.invoke({
    "messages": [("human", "What is 25 * 4 and who invented calculus?")]
})

from langgraph.graph import StateGraph, END from typing import TypedDict, Annotated, List import operator
class PlanExecuteState(TypedDict): input: str plan: List[str] current_step: int results: Annotated[List[str], operator.add] final_answer: str
def planner(state: PlanExecuteState) -> PlanExecuteState: """Create a plan of steps.""" prompt = f"Create a step-by-step plan to answer: {state['input']}" response = model.invoke(prompt) steps = parse_steps(response.content) return {"plan": steps, "current_step": 0}
def executor(state: PlanExecuteState) -> PlanExecuteState: """Execute current step.""" step = state["plan"][state["current_step"]] result = model.invoke(f"Execute this step: {step}") return {"results": [result.content], "current_step": state["current_step"] + 1}
def should_continue(state: PlanExecuteState) -> str: if state["current_step"] >= len(state["plan"]): return "synthesize" return "execute"
def synthesizer(state: PlanExecuteState) -> PlanExecuteState: """Combine results into final answer.""" all_results = "\n".join(state["results"]) prompt = f"Synthesize these results into a final answer:\n{all_results}" response = model.invoke(prompt) return {"final_answer": response.content}
# Build graph graph = StateGraph(PlanExecuteState) graph.add_node("plan", planner) graph.add_node("execute", executor) graph.add_node("synthesize", synthesizer)
graph.set_entry_point("plan") graph.add_edge("plan", "execute") graph.add_conditional_edges("execute", should_continue) graph.add_edge("synthesize", END)
agent = graph.compile()

from langchain_core.tools import tool, StructuredTool
from pydantic import BaseModel, Field

# Simple tool with decorator
@tool
def search(query: str) -> str:
    """Search the web for information about a topic.
    Use for: facts, recent events, company info, pricing.
    Do NOT use for: math, code execution, structured data.
    """
    return f"Search results for: {query}"

# Tool with complex input
class CalculatorInput(BaseModel):
    expression: str = Field(description="Mathematical expression")
    precision: int = Field(default=2, description="Decimal places")

@tool(args_schema=CalculatorInput)
def calculate(expression: str, precision: int = 2) -> str:
    """Calculate a mathematical expression."""
    result = eval(expression)
    return f"{result:.{precision}f}"

# Tool with error handling
@tool(handle_tool_error=True)
def risky_tool(input: str) -> str:
    """A tool that might fail."""
    if not input:
        raise ToolException("Input cannot be empty")
    return f"Processed: {input}"

# Simple tool
@tool
def search(query: str) -> str:
    """Search the web for information."""
    return f"Results for: {query}"

# Tool with validation
class CalculatorInput(BaseModel):
    expression: str = Field(description="Mathematical expression")
    precision: int = Field(default=2, description="Decimal places")

@tool(args_schema=CalculatorInput)
def calculate(expression: str, precision: int = 2) -> str:
    """Calculate a mathematical expression."""
    result = eval(expression)
    return f"{result:.{precision}f}"

# Dynamic tool creation
def create_api_tool(api_name: str, base_url: str):
    @tool(name=f"{api_name}_api")
    def api_tool(endpoint: str, params: dict = None) -> str:
        f"""Call the {api_name} API."""
        return f"API response from {base_url}/{endpoint}"
    return api_tool
